              boxShadow: "0 2px 8px rgba(0,0,0,0.08)",
            }}
            formatter={(value: number, name: string) => {
              const label = name === "users" ? "ユーザー" : "PV"
              return [value.toLocaleString(), label]
            }}
          />
          <Area
            type="monotone"
            dataKey="pageviews"
            stroke="rgba(0, 49, 216, 0.5)"
            fill="rgba(0, 49, 216, 0.08)"
