            dataKey="users"
            stroke="#41C9B4"
            fill="rgba(65, 201, 180, 0.12)"
            strokeWidth={2}
            dot={false}
            activeDot={{ r: 3, fill: "#41C9B4" }}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  )
}

